#!/usr/bin/env bash\nset -euo pipefail\n\n# 紐⑹쟻:\n# - 遺?섎뒗 tools-once Pod ?덉뿉???ㅽ뻾\n# - 留덉?留됱뿉 nodes/deploy ?ㅻ깄?룹? "濡쒖뺄(???ㅽ겕由쏀듃 ?ㅽ뻾 ?몄뒪??"?먯꽌 李띿뼱??異쒕젰\n#\n# ?듭떖:\n# - ?뚮뱶 ?대? python(sqs_load_real_concert5.py)? 留덉?留됱뿉 HOST_SNAPSHOT_CMD 留덉빱留?異쒕젰\n# - ???ㅽ겕由쏀듃媛 洹?留덉빱瑜?媛먯??댁꽌 濡쒖뺄?먯꽌 ?ㅻ깄??sh瑜??ㅽ뻾?쒕떎\n#\n# ?ъ슜:\n#   bash ./?먰댋??sh --show-id 100 -E 1 -T 10\n\nNS="${TICKETING_NAMESPACE:-ticketing}"\nPOD="${TOOLS_ONCE_POD:-tools-once}"\n\nREPO_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]:-$0}")/.." && pwd)"\nSNAPSHOT_SH="${SNAPSHOT_SH:-$REPO_ROOT/scripts/k8s-snapshot-host.sh}"\n\n# python?먭쾶 "?몄뒪?몄뿉???ㅽ뻾???ㅻ깄??而ㅻ㎤??瑜?臾몄옄?대줈 ?섍꺼以??
POST_HOST_SNAPSHOT_SH="${POST_HOST_SNAPSHOT_SH:-bash \"$SNAPSHOT_SH\"}"\n\ntmp_err="$(mktemp)"\ntmp_out="$(mktemp)"\ncleanup() { rm -f "$tmp_err" "$tmp_out"; }\ntrap cleanup EXIT\n\nset +e\nkubectl -n "$NS" exec -it "$POD" -- sh -lc "\n  set -e\n  cd /work/ticketing-db/terraform\n  export POST_HOST_SNAPSHOT_SH='${POST_HOST_SNAPSHOT_SH}'\n  python3 ../scripts/sqs_load_real_concert5.py $*\n" >"$tmp_out" 2>"$tmp_err"\nrc=$?\nset -e\n\ncat "$tmp_out"\ncat "$tmp_err" >&2\n\n# 留덉빱 媛먯? ??濡쒖뺄?먯꽌 ?ㅽ뻾\ncmd="$(awk -F'HOST_SNAPSHOT_CMD: ' '/HOST_SNAPSHOT_CMD: /{print $2; exit}' "$tmp_err" | sed 's/[[:space:]]*$//')"\nif [[ -n "$cmd" ]]; then\n  echo "-----------------------------------------------------------" >&2\n  echo "[host] running snapshot: $cmd" >&2\n  echo "-----------------------------------------------------------" >&2\n  # shellcheck disable=SC2086\n  eval "$cmd"\nfi\n\nexit "$rc"\n\n